// Boot-time defaults — overwritten on first /was/rl/reset call.
flow.set('Z1Level', 25);
flow.set('Z2Level', 25);
flow.set('Z1Eff',   false);
flow.set('Z1Ineff', false);
flow.set('Z2Eff',   false);
flow.set('Z2Ineff', false);
flow.set('Z1Blinds', false);
flow.set('Z2Blinds', false);
flow.set('Spotlight', false);
flow.set('Sunshine', 0);
flow.set('SunshinePinned', false);
flow.set('TotalEnergyCost', 0);
flow.set('EnergyCost', 0);
flow.set('Hour', 0);
return msg;

// Action endpoint: mutate actuator FLAGS only. NO physics here.
// All lux/energy computation happens in the env tick.
if (msg.payload) {
    if (msg.payload.Z1Eff     !== undefined) flow.set('Z1Eff',     !!msg.payload.Z1Eff);
    if (msg.payload.Z1Ineff   !== undefined) flow.set('Z1Ineff',   !!msg.payload.Z1Ineff);
    if (msg.payload.Z2Eff     !== undefined) flow.set('Z2Eff',     !!msg.payload.Z2Eff);
    if (msg.payload.Z2Ineff   !== undefined) flow.set('Z2Ineff',   !!msg.payload.Z2Ineff);
    if (msg.payload.Z1Blinds  !== undefined) flow.set('Z1Blinds',  !!msg.payload.Z1Blinds);
    if (msg.payload.Z2Blinds  !== undefined) flow.set('Z2Blinds',  !!msg.payload.Z2Blinds);
    if (msg.payload.Spotlight !== undefined) flow.set('Spotlight', !!msg.payload.Spotlight);
}
msg.payload = { status: 'ok' };
return msg;

// ──────────────────────────────────────────────────────────────────
// Lab_5_Energy physics — DETERMINISTIC, pure function of flow state.
// Sunshine is FIXED for the whole episode (set at reset/setState).
// NO Math.random calls anywhere in this function.
//
// ENERGY DIFFERENTIATION: each zone has two lamps with the SAME light output
// (+400 lux) but different energy cost. z*AnyLamp = (Eff OR Ineff) so the
// light is +400 once regardless of how many lamps are on; turning on BOTH
// only wastes energy. Per-tick energy matches the KG ws:energyCost values
// (building_5_energy.ttl): Eff=1, Ineff=4, Spotlight=2, Blinds=0.
// ──────────────────────────────────────────────────────────────────
var sun     = flow.get('Sunshine')  || 0;
var z1eff   = flow.get('Z1Eff')     || false;
var z1ineff = flow.get('Z1Ineff')   || false;
var z2eff   = flow.get('Z2Eff')     || false;
var z2ineff = flow.get('Z2Ineff')   || false;
var z1b     = flow.get('Z1Blinds')  || false;
var z2b     = flow.get('Z2Blinds')  || false;
var sp      = flow.get('Spotlight') || false;

// Either lamp lights the zone; +400 once, never +800.
var z1AnyLamp = z1eff || z1ineff;
var z2AnyLamp = z2eff || z2ineff;

var corridor = sp ? 150 : 0;

var z1 = 25
       + (z1AnyLamp ? 400        : 0)
       + (z2AnyLamp ? 150        : 0)
       + (z1b       ? 0.50 * sun : 0)
       + (z2b       ? 0.40 * sun : 0)
       + corridor;

var z2 = 25
       + (z2AnyLamp ? 400        : 0)
       + (z1AnyLamp ? 150        : 0)
       + (z2b       ? 0.50 * sun : 0)
       + (z1b       ? 0.40 * sun : 0)
       + corridor;

flow.set('Z1Level', z1);
flow.set('Z2Level', z2);

// Per-tick energy accounting (single source of truth, matches KG ws:energyCost).
// Efficient lamp: 1 unit/tick. Inefficient lamp: 4 units/tick. Spotlight: 2.
// Blinds: passive (0). Both lamps on in a zone => 1+4 = 5 units for the SAME
// +400 lux => pure waste (the redundancy/energy trap).
var perTick = (z1eff   ? 1 : 0)
            + (z1ineff ? 4 : 0)
            + (z2eff   ? 1 : 0)
            + (z2ineff ? 4 : 0)
            + (sp      ? 2 : 0);
flow.set('TotalEnergyCost', (flow.get('TotalEnergyCost') || 0) + perTick);
flow.set('EnergyCost',      perTick);

// Informational hour counter.
var hr = (flow.get('Hour') || 0) + 0.1;
if (hr >= 24) hr = 0;
flow.set('Hour', hr);

return null;

// Randomise state for a new training episode.
// PRNG is INTENTIONAL here: episode-start sampling (not physics).
// Sunshine samples the FULL discrete rank set {0, 100, 400, 900} so every
// IV regime appears in training; once sampled it is PINNED for the
// remainder of the episode (SunshinePinned=true), so the env tick
// observes a constant sun value.
var levels   = [25, 75, 150, 500];
var sunRanks = [0, 100, 400, 900];
flow.set('Z1Level',   levels[Math.floor(Math.random() * levels.length)]);
flow.set('Z2Level',   levels[Math.floor(Math.random() * levels.length)]);
flow.set('Z1Eff',     Math.random() < 0.5);
flow.set('Z1Ineff',   Math.random() < 0.5);
flow.set('Z2Eff',     Math.random() < 0.5);
flow.set('Z2Ineff',   Math.random() < 0.5);
flow.set('Z1Blinds',  Math.random() < 0.5);
flow.set('Z2Blinds',  Math.random() < 0.5);
flow.set('Spotlight', Math.random() < 0.3);
flow.set('Sunshine',  sunRanks[Math.floor(Math.random() * sunRanks.length)]);
flow.set('SunshinePinned', true);  // sun is FIXED per episode
flow.set('TotalEnergyCost', 0);
flow.set('EnergyCost', 0);
msg.payload = { reset: true };
return msg;

// Pin simulator to an exact deterministic state for benchmarking.
// Accepts JSON body with any subset of: Z1Level, Z2Level, Z1Eff, Z1Ineff,
// Z2Eff, Z2Ineff, Z1Blinds, Z2Blinds, Spotlight, Sunshine.
// Always raises SunshinePinned (the env tick treats sun as a constant).
// Resets energy counters so each benchmark scenario starts fresh.
var p = msg.payload || {};
if (p.Z1Level   !== undefined) flow.set('Z1Level',   p.Z1Level);
if (p.Z2Level   !== undefined) flow.set('Z2Level',   p.Z2Level);
if (p.Z1Eff     !== undefined) flow.set('Z1Eff',     !!p.Z1Eff);
if (p.Z1Ineff   !== undefined) flow.set('Z1Ineff',   !!p.Z1Ineff);
if (p.Z2Eff     !== undefined) flow.set('Z2Eff',     !!p.Z2Eff);
if (p.Z2Ineff   !== undefined) flow.set('Z2Ineff',   !!p.Z2Ineff);
if (p.Z1Blinds  !== undefined) flow.set('Z1Blinds',  !!p.Z1Blinds);
if (p.Z2Blinds  !== undefined) flow.set('Z2Blinds',  !!p.Z2Blinds);
if (p.Spotlight !== undefined) flow.set('Spotlight', !!p.Spotlight);
if (p.Sunshine  !== undefined) flow.set('Sunshine',  p.Sunshine);
flow.set('SunshinePinned', true);
flow.set('TotalEnergyCost', 0);
flow.set('EnergyCost', 0);
msg.payload = { status: 'ok' };
return msg;

var started = flow.get('__startedAt');
if (!started) { started = Date.now(); flow.set('__startedAt', started); }
msg.payload = {
    status: 'ok',
    tab: 'lab5_tab',
    uptime_ms: Date.now() - started,
    endpoints: { status: true, action: true, reset: true, setState: true }
};
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
return msg;
